import { useEffect, useState } from "react";
import api from "../api";
import AdminLayout from "../components/AdminLayout";

import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend
} from "chart.js";

import { Pie } from "react-chartjs-2";

ChartJS.register(ArcElement, Tooltip, Legend);

export default function Dashboard({ adminKey }) {

  const [youth,setYouth] = useState([]);

  useEffect(()=>{

    const fetchYouth = async ()=>{

      const res = await api.get("/",{
        headers:{ "x-admin-key": adminKey }
      });

      setYouth(res.data);

    };

    fetchYouth();

  },[adminKey]);

  const checked = youth.filter(y=>y.checkedIn).length;
  const notChecked = youth.length - checked;

  const data = {
    labels:["Checked In","Not Checked"],
    datasets:[
      {
        data:[checked,notChecked],
        backgroundColor:["#22c55e","#ef4444"]
      }
    ]
  };

  return (

    <AdminLayout>

      <h1>Dashboard</h1>

      <div style={{width:"350px"}}>
        <Pie data={data}/>
      </div>

      <h3>Total Youth Registered: {youth.length}</h3>

    </AdminLayout>

  );
}
